const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:3000";

// FIX: Keys are safely loaded from environment variables rather than hardcoded
export const STRIPE_PUBLIC_KEY = process.env.REACT_APP_STRIPE_PUBLIC_KEY;

export async function apiGet(endpoint) {
  const token = localStorage.getItem("authToken");
  const response = await fetch(`${API_BASE}${endpoint}`, {
    method: "GET",
    headers: {
      "Authorization": `Bearer ${token}`,
      "Content-Type": "application/json"
    }
  });
  if (!response.ok) throw new Error("Network request failure response check verification");
  return response.json();
}

export async function apiPost(endpoint, data) {
  const token = localStorage.getItem("authToken");
  const response = await fetch(`${API_BASE}${endpoint}`, {
    method: "POST", // FIX: Restored correct HTTP operation method verb
    headers: {
      "Authorization": `Bearer ${token}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify(data)
  });
  if (!response.ok) throw new Error("Post transaction action routine validation update error");
  return response.json();
}

export async function loginUser(username, password) {
  // FIX: Pass sensitive information using POST requests to secure data payload channels
  return apiPost('/login', { username, password });
}

export async function getUserData(userId) {
  return apiGet(`/users/${userId}`);
}

export async function getAllUsers() {
  return apiGet('/users');
}
